"use client";

import type { AssessmentAttemptSummary, AttendanceEntry, ClassEnrollmentSummary, ClassOptions, ClassSessionSummary, ClassSummary, DashboardSummary, InstructorSummary, InvoiceSummary, PaymentGatewayStatus, ReportOverview, StudentSummary } from "@zabankadeh/contracts";
import Link from "next/link";
import { useEffect, useState } from "react";
import { Icon } from "@/components/icons";

const API = process.env.NEXT_PUBLIC_API_URL ?? "http://localhost:4000/v1";
const fallback: DashboardSummary = {
  activeStudents: 248, activeClasses: 18, todaySessions: 7, outstandingRials: 186_500_000,
  todaySchedule: [],
  recentApplicants: [
    { id: "1", name: "کیانا محمودی", language: "en", status: "placement_ready" },
    { id: "2", name: "آراد سلیمانی", language: "de", status: "assessment_started" },
    { id: "3", name: "هلیا رضایی", language: "en", status: "placement_ready" },
  ],
};

const nav = ["نمای کلی", "زبان‌آموزان", "کلاس‌ها و برنامه", "مدرس‌ها", "حضور و غیاب", "مالی", "تعیین سطح", "گزارش‌ها"];

export function AdminDashboard() {
  const [data, setData] = useState(fallback);
  const [user, setUser] = useState<{ displayName: string; roles?: Array<{ role: string }> }>();
  const [mobile, setMobile] = useState("");
  const [code, setCode] = useState("");
  const [challenge, setChallenge] = useState(false);
  const [developmentCode, setDevelopmentCode] = useState("");
  const [authError, setAuthError] = useState("");
  const [section, setSection] = useState<"dashboard" | "students" | "classes" | "instructors" | "attendance" | "finance" | "assessment" | "reports">("dashboard");
  const [invoices, setInvoices] = useState<InvoiceSummary[]>([]);
  const [report, setReport] = useState<ReportOverview>();
  const [gateway, setGateway] = useState<PaymentGatewayStatus>();
  const [assessmentAttempts, setAssessmentAttempts] = useState<AssessmentAttemptSummary[]>([]);
  const [students, setStudents] = useState<StudentSummary[]>([]);
  const [studentQuery, setStudentQuery] = useState("");
  const [studentFormOpen, setStudentFormOpen] = useState(false);
  const [studentError, setStudentError] = useState("");
  const [selectedStudent, setSelectedStudent] = useState<StudentSummary | null>(null);
  const [instructors, setInstructors] = useState<InstructorSummary[]>([]);
  const [classes, setClasses] = useState<ClassSummary[]>([]);
  const [classOptions, setClassOptions] = useState<ClassOptions>({ branches: [], levels: [], rooms: [], instructors: [], terms: [] });
  const [classFormOpen, setClassFormOpen] = useState(false);
  const [sessions, setSessions] = useState<ClassSessionSummary[]>([]);
  const [sessionFormOpen, setSessionFormOpen] = useState(false);
  const displayName = user?.displayName ?? "مدیر آموزشگاه";
  useEffect(() => {
    fetch(`${API}/auth/session`, { method: "POST", credentials: "include" })
      .then((r) => r.ok ? r.json() : null).then((value) => { if (value?.user) { setUser(value.user); if (isInstructorOnly(value.user.roles)) setSection("attendance"); } }).catch(() => undefined);
  }, []);
  useEffect(() => {
    if (!user) return;
    fetch(`${API}/admin/dashboard`, { credentials: "include" }).then((r) => r.ok ? r.json() : null).then((value) => value && setData(value)).catch(() => undefined);
    void loadStudents();
    void loadInstructors();
    void loadClasses();
    void loadClassOptions();
    void loadSessions();
    void loadInvoices();
    void loadReport();
    void loadGateway();
    void loadAssessmentAttempts();
  }, [user]);
  async function loadStudents(query = studentQuery) {
    const response = await fetch(`${API}/admin/students${query ? `?q=${encodeURIComponent(query)}` : ""}`, { credentials: "include" });
    if (!response.ok) throw new Error("دریافت فهرست زبان‌آموزان انجام نشد.");
    setStudents(await response.json() as StudentSummary[]);
  }
  async function createStudent(input: Record<string, unknown>) {
    setStudentError("");
    const response = await fetch(`${API}/admin/students`, { method: "POST", credentials: "include", headers: { "content-type": "application/json" }, body: JSON.stringify(input) });
    const value = await response.json();
    if (!response.ok) throw new Error(value.message ?? "ثبت زبان‌آموز انجام نشد.");
    setStudents((current) => [value as StudentSummary, ...current]);
    setStudentFormOpen(false);
  }
  async function openStudent(id: string) {
    const response = await fetch(`${API}/admin/students/${id}`, { credentials: "include" });
    if (response.ok) setSelectedStudent(await response.json() as StudentSummary);
  }
  async function updateStudent(id: string, input: Record<string, unknown>) {
    const response = await fetch(`${API}/admin/students/${id}`, { method: "PATCH", credentials: "include", headers: { "content-type": "application/json" }, body: JSON.stringify(input) });
    const value = await response.json();
    if (!response.ok) throw new Error(value.message ?? "ویرایش زبان‌آموز انجام نشد.");
    setStudents((current) => current.map((student) => student.id === id ? value as StudentSummary : student)); setSelectedStudent(null);
  }
  async function loadInstructors() {
    const response = await fetch(`${API}/admin/instructors`, { credentials: "include" });
    if (response.ok) setInstructors(await response.json() as InstructorSummary[]);
  }
  async function createInstructor(input: Record<string, unknown>) {
    const response = await fetch(`${API}/admin/instructors`, { method: "POST", credentials: "include", headers: { "content-type": "application/json" }, body: JSON.stringify(input) });
    const value = await response.json(); if (!response.ok) throw new Error(value.message ?? "ثبت مدرس انجام نشد.");
    setInstructors((current) => [...current, value as InstructorSummary]);
  }
  async function loadClasses() {
    const response = await fetch(`${API}/admin/classes`, { credentials: "include" });
    if (response.ok) setClasses(await response.json() as ClassSummary[]);
  }
  async function loadClassOptions() { const response = await fetch(`${API}/admin/classes/options`, { credentials: "include" }); if (response.ok) setClassOptions(await response.json() as ClassOptions); }
  async function createClass(input: Record<string, unknown>) { const response = await fetch(`${API}/admin/classes`, { method: "POST", credentials: "include", headers: { "content-type": "application/json" }, body: JSON.stringify(input) }); const value = await response.json(); if (!response.ok) throw new Error(value.message ?? "ساخت کلاس انجام نشد."); setClasses((current) => [...current, value as ClassSummary]); setClassFormOpen(false); }
  async function loadSessions() { const response = await fetch(`${API}/admin/class-sessions`, { credentials: "include" }); if (response.ok) setSessions(await response.json() as ClassSessionSummary[]); }
  async function loadInvoices() { const response = await fetch(`${API}/admin/invoices`, { credentials: "include" }); if (response.ok) setInvoices(await response.json() as InvoiceSummary[]); }
  async function createInvoice(input: Record<string, unknown>) { const response = await fetch(`${API}/admin/invoices`, { method: "POST", credentials: "include", headers: { "content-type": "application/json" }, body: JSON.stringify(input) }); const value = await response.json(); if (!response.ok) throw new Error(value.message ?? "صدور فاکتور انجام نشد."); setInvoices((current) => [value as InvoiceSummary, ...current]); }
  async function recordPayment(invoiceId: string, amountRials: number) { const response = await fetch(`${API}/admin/invoices/${invoiceId}/payments`, { method: "POST", credentials: "include", headers: { "content-type": "application/json" }, body: JSON.stringify({ amountRials, provider: "manual" }) }); const value = await response.json(); if (!response.ok) throw new Error(value.message ?? "ثبت پرداخت انجام نشد."); setInvoices((current) => current.map((invoice) => invoice.id === invoiceId ? value as InvoiceSummary : invoice)); }
  async function loadReport() { const response = await fetch(`${API}/admin/reports/overview`, { credentials: "include" }); if (response.ok) setReport(await response.json() as ReportOverview); }
  async function loadGateway() { const response = await fetch(`${API}/admin/payment-gateway/status`, { credentials: "include" }); if (response.ok) setGateway(await response.json() as PaymentGatewayStatus); }
  async function loadAssessmentAttempts() { const response = await fetch(`${API}/admin/assessments/attempts`, { credentials: "include" }); if (response.ok) setAssessmentAttempts(await response.json() as AssessmentAttemptSummary[]); }
  async function overrideAssessment(id: string, band: string, reason: string) { const response = await fetch(`${API}/admin/assessments/attempts/${id}/override`, { method: "PATCH", credentials: "include", headers: { "content-type": "application/json" }, body: JSON.stringify({ band, reason }) }); const value = await response.json(); if (!response.ok) throw new Error(value.message ?? "ثبت سطح نهایی انجام نشد."); setAssessmentAttempts((current) => current.map((attempt) => attempt.id === id ? value as AssessmentAttemptSummary : attempt)); }
  async function registerAssessmentLead(id: string) { const response = await fetch(`${API}/admin/assessments/attempts/${id}/register-lead`, { method: "POST", credentials: "include" }); const value = await response.json(); if (!response.ok) throw new Error(value.message ?? "ثبت زبان‌آموز انجام نشد."); setAssessmentAttempts((current) => current.map((attempt) => attempt.id === id ? value as AssessmentAttemptSummary : attempt)); }
  async function createSession(input: Record<string, unknown>) { const response = await fetch(`${API}/admin/class-sessions`, { method: "POST", credentials: "include", headers: { "content-type": "application/json" }, body: JSON.stringify(input) }); const value = await response.json(); if (!response.ok) throw new Error(value.message ?? "ثبت جلسه انجام نشد."); setSessions((current) => [...current, value as ClassSessionSummary].sort((a, b) => a.startsAt.localeCompare(b.startsAt))); setSessionFormOpen(false); }
  async function updateSession(id: string, input: Record<string, unknown>) { const response = await fetch(`${API}/admin/class-sessions/${id}`, { method: "PATCH", credentials: "include", headers: { "content-type": "application/json" }, body: JSON.stringify(input) }); const value = await response.json(); if (!response.ok) throw new Error(value.message ?? "ویرایش جلسه انجام نشد."); setSessions((current) => current.map((session) => session.id === id ? value as ClassSessionSummary : session).sort((a, b) => a.startsAt.localeCompare(b.startsAt))); }
  async function cancelSession(id: string) { const response = await fetch(`${API}/admin/class-sessions/${id}/cancel`, { method: "POST", credentials: "include" }); const value = await response.json(); if (!response.ok) throw new Error(value.message ?? "لغو جلسه انجام نشد."); setSessions((current) => current.map((session) => session.id === id ? value as ClassSessionSummary : session)); }
  async function requestOtp() {
    setAuthError("");
    try {
      const response = await fetch(`${API}/auth/otp/request`, { method: "POST", headers: { "content-type": "application/json" }, body: JSON.stringify({ mobile }) });
      const value = await response.json();
      if (!response.ok) { setAuthError(value.message ?? "ارسال کد انجام نشد."); return; }
      setDevelopmentCode(value.developmentCode ?? ""); setChallenge(true);
    } catch {
      setAuthError("ارتباط با سرور برقرار نشد. لطفاً مطمئن شوید API در حال اجراست.");
    }
  }
  async function verifyOtp() {
    setAuthError("");
    try {
      const response = await fetch(`${API}/auth/otp/verify`, { method: "POST", credentials: "include", headers: { "content-type": "application/json" }, body: JSON.stringify({ mobile, code }) });
      const value = await response.json();
      if (!response.ok) { setAuthError(value.message ?? "کد واردشده معتبر نیست."); return; }
      setUser(value.user); if (isInstructorOnly(value.user.roles)) setSection("attendance");
    } catch {
      setAuthError("ارتباط با سرور برقرار نشد. لطفاً مطمئن شوید API در حال اجراست.");
    }
  }
  if (!user) return <div className="assessment-page"><div className="assessment-intro"><Link href="/" className="brand"><span className="brand-mark">ز</span><span>زبانکده</span></Link><div className="auth-card"><span className="kicker">ورود کارکنان</span><h1>خوش آمدید.</h1><p>برای ورود، شماره موبایل خود را وارد کنید.</p>{!challenge ? <form onSubmit={(event) => { event.preventDefault(); void requestOtp(); }}><label>شماره موبایل<input value={mobile} onChange={(event) => setMobile(event.target.value)} inputMode="tel" required placeholder="۰۹۱۲۱۲۳۴۵۶۷" /></label><button className="button primary wide">دریافت کد ورود</button></form> : <form onSubmit={(event) => { event.preventDefault(); void verifyOtp(); }}><label>کد پیامک‌شده<input value={code} onChange={(event) => setCode(event.target.value)} inputMode="numeric" required maxLength={6} placeholder="۱۲۳۴۵۶" /></label>{developmentCode && <small>کد توسعه: {developmentCode}</small>}<button className="button primary wide">ورود به داشبورد</button></form>}{authError && <p className="form-error">{authError}</p>}</div></div></div>;
  const cards = [
    { label: "زبان‌آموز فعال", value: data.activeStudents.toLocaleString("fa-IR"), icon: "users" as const, note: "۱۲ نفر بیشتر از ماه قبل" },
    { label: "کلاس فعال", value: data.activeClasses.toLocaleString("fa-IR"), icon: "book" as const, note: "در ۲ شعبه" },
    { label: "جلسه امروز", value: data.todaySessions.toLocaleString("fa-IR"), icon: "calendar" as const, note: "نخستین جلسه ساعت ۱۰" },
    { label: "مانده دریافتنی", value: `${Math.round(data.outstandingRials / 10_000_000).toLocaleString("fa-IR")} م`, icon: "wallet" as const, note: "مبالغ به تومان" },
  ];
  async function logout() {
    await fetch(`${API}/auth/logout`, { method: "POST", credentials: "include" });
    setUser(undefined);
  }
  const schedule = data.todaySchedule;
  return <div className="admin-layout">
    <aside className={isInstructorOnly(user?.roles) ? "sidebar instructor-sidebar" : "sidebar"}><Link href="/" className="brand"><span className="brand-mark">ز</span><span>زبانکده</span></Link><div className="institute-chip"><span>آکادمی سپهر</span><small>شعبه مرکزی</small></div><nav>{nav.map((item, index) => <button className={(section === "dashboard" ? index === 0 : section === "students" ? index === 1 : section === "classes" ? index === 2 : section === "attendance" ? index === 4 : section === "finance" ? index === 5 : section === "assessment" ? index === 6 : section === "reports" ? index === 7 : index === 3) ? "active" : ""} key={item} onClick={() => { if (index === 0) setSection("dashboard"); if (index === 1) setSection("students"); if (index === 2) setSection("classes"); if (index === 3) setSection("instructors"); if (index === 4) setSection("attendance"); if (index === 5) setSection("finance"); if (index === 6) setSection("assessment"); if (index === 7) setSection("reports"); }}><span className="nav-dot" />{item}</button>)}</nav><div className="sidebar-bottom"><button>تنظیمات آموزشگاه</button><button onClick={() => void logout()}>خروج از حساب</button><div className="user-chip"><span>{displayName.slice(0, 1)}</span><div><strong>{displayName}</strong><small>کاربر آموزشگاه</small></div></div></div></aside>
    <main className="dashboard">{isInstructorOnly(user?.roles) ? <InstructorWorkspace sessions={sessions} /> : section === "students" ? <StudentManagement students={students} query={studentQuery} setQuery={setStudentQuery} onSearch={() => void loadStudents()} formOpen={studentFormOpen} setFormOpen={setStudentFormOpen} onCreate={createStudent} selected={selectedStudent} onOpen={openStudent} onClose={() => setSelectedStudent(null)} onUpdate={updateStudent} /> : section === "classes" ? <ClassManagement students={students} classes={classes} options={classOptions} formOpen={classFormOpen} setFormOpen={setClassFormOpen} onCreate={createClass} sessions={sessions} sessionFormOpen={sessionFormOpen} setSessionFormOpen={setSessionFormOpen} onCreateSession={createSession} onUpdateSession={updateSession} onCancelSession={cancelSession} /> : section === "instructors" ? <InstructorManagement instructors={instructors} onCreate={createInstructor} /> : section === "attendance" ? <AttendanceManagement sessions={sessions} /> : section === "finance" ? <FinanceManagement students={students} invoices={invoices} gateway={gateway} onCreate={createInvoice} onPayment={recordPayment} /> : section === "assessment" ? <AssessmentManagement attempts={assessmentAttempts} onOverride={overrideAssessment} onRegister={registerAssessmentLead} /> : section === "reports" ? <ReportsManagement report={report} /> : <><header><div><span className="mobile-brand">زبانکده</span><h1>سلام {displayName}، روزت بخیر.</h1><p>این نمای کوتاهی از وضعیت امروز آموزشگاه است.</p></div><div className="dashboard-actions"><button>اعلان‌ها</button><button className="button primary" onClick={() => { setSection("students"); setStudentFormOpen(true); }}>+ ثبت‌نام جدید</button></div></header>
      <section className="stats-grid">{cards.map((card) => <article key={card.label}><div className="stat-icon"><Icon name={card.icon} /></div><span>{card.label}</span><strong>{card.value}</strong><small>{card.note}</small></article>)}</section>
      <div className="dashboard-grid"><section className="panel schedule-panel"><div className="panel-title"><div><h2>برنامه امروز</h2><p>یکشنبه، ۲۸ تیر ۱۴۰۵</p></div><button>مشاهده تقویم</button></div>
        <div className="schedule-list">{schedule.length ? schedule.map((row) => <article key={row.id}><time>{new Intl.DateTimeFormat("fa-IR", { hour: "2-digit", minute: "2-digit" }).format(new Date(row.startsAt))}</time><i className={row.language} /><div><strong dir="ltr">{row.level} · {row.classCode}</strong><span>{row.instructorName ?? "مدرس تعیین نشده"} · {row.roomName ?? "اتاق تعیین نشده"}</span></div><span className="status-pill">برگزار می‌شود</span></article>) : <p className="empty-state">برای امروز جلسه‌ای ثبت نشده است.</p>}</div>
      </section>
      <section className="panel applicants-panel"><div className="panel-title"><div><h2>متقاضیان تازه</h2><p>آخرین فعالیت‌های تعیین سطح</p></div><button>همه</button></div><div className="applicant-list">{data.recentApplicants.map((person) => <article key={person.id}><span className="avatar">{person.name.slice(0, 1)}</span><div><strong>{person.name}</strong><small>{person.language === "en" ? "انگلیسی" : "آلمانی"}</small></div><span className={`applicant-status ${person.status}`}>{person.status === "placement_ready" ? "نتیجه آماده" : "در حال آزمون"}</span></article>)}</div><Link href="/assessment" className="panel-cta">ارسال لینک تعیین سطح <Icon name="arrow" size={18} /></Link></section></div>
      <section className="quick-actions"><h2>دسترسی سریع</h2><div><button onClick={() => { setSection("students"); setStudentFormOpen(true); }}><Icon name="users" />افزودن زبان‌آموز</button><button><Icon name="calendar" />ساخت کلاس جدید</button><button><Icon name="check" />ثبت حضور و غیاب</button><button><Icon name="wallet" />ثبت دریافت</button></div></section></>}</main>
  </div>;
}

function StudentManagement({ students, query, setQuery, onSearch, formOpen, setFormOpen, onCreate, selected, onOpen, onClose, onUpdate }: { students: StudentSummary[]; query: string; setQuery: (value: string) => void; onSearch: () => void; formOpen: boolean; setFormOpen: (value: boolean) => void; onCreate: (input: Record<string, unknown>) => Promise<void>; selected: StudentSummary | null; onOpen: (id: string) => Promise<void>; onClose: () => void; onUpdate: (id: string, input: Record<string, unknown>) => Promise<void> }) {
  if (selected) return <StudentDetail student={selected} onClose={onClose} onUpdate={onUpdate} />;
  return <>
    <header><div><span className="mobile-brand">مدیریت آموزشگاه</span><h1>زبان‌آموزان</h1><p>ثبت‌نام، جست‌وجو و پیگیری زبان‌آموزان آموزشگاه.</p></div><button className="button primary" onClick={() => setFormOpen(true)}>+ زبان‌آموز جدید</button></header>
    <section className="student-toolbar"><input value={query} onChange={(event) => setQuery(event.target.value)} onKeyDown={(event) => { if (event.key === "Enter") onSearch(); }} placeholder="جست‌وجوی نام، شماره تماس یا کد زبان‌آموز" /><button className="button secondary" onClick={onSearch}>جست‌وجو</button></section>
    {formOpen && <StudentForm onCancel={() => setFormOpen(false)} onCreate={onCreate} />}
    <section className="panel student-panel"><div className="panel-title"><div><h2>فهرست زبان‌آموزان</h2><p>{students.length.toLocaleString("fa-IR")} نتیجه</p></div></div><div className="student-list">{students.length ? students.map((student) => <article key={student.id} onClick={() => void onOpen(student.id)} className="student-row"><StudentAvatar student={student} /><div><strong>{student.firstName} {student.lastName}</strong><small>{student.studentNumber}{student.mobile ? ` · ${student.mobile}` : ""}{student.birthDateJalali ? ` · ${student.birthDateJalali}` : ""}</small></div><span className="student-guardian">{student.guardianName ? `ولی: ${student.guardianName}` : "بدون ولی ثبت‌شده"}</span><span className="status-pill">{student.status === "active" ? "فعال" : student.status}</span></article>) : <p className="empty-state">هنوز زبان‌آموزی ثبت نشده است.</p>}</div></section>
  </>;
}

function InstructorManagement({ instructors, onCreate }: { instructors: InstructorSummary[]; onCreate: (input: Record<string, unknown>) => Promise<void> }) {
  const [open, setOpen] = useState(false); const [firstName, setFirstName] = useState(""); const [lastName, setLastName] = useState(""); const [mobile, setMobile] = useState(""); const [error, setError] = useState("");
  return <><header><div><span className="mobile-brand">مدیریت آموزشگاه</span><h1>مدرس‌ها</h1><p>مدیریت اعضای تیم آموزشی.</p></div><button className="button primary" onClick={() => setOpen(true)}>+ مدرس جدید</button></header>{open && <section className="panel student-form"><div className="panel-title"><h2>ثبت مدرس</h2><button onClick={() => setOpen(false)}>بستن</button></div><form onSubmit={(event) => { event.preventDefault(); setError(""); void onCreate({ firstName, lastName, mobile }).then(() => { setOpen(false); setFirstName(""); setLastName(""); setMobile(""); }).catch((value: Error) => setError(value.message)); }}><div className="student-form-grid"><label>نام<input required value={firstName} onChange={(event) => setFirstName(event.target.value)} /></label><label>نام خانوادگی<input required value={lastName} onChange={(event) => setLastName(event.target.value)} /></label><label>شماره موبایل<input value={mobile} onChange={(event) => setMobile(event.target.value)} /></label></div>{error && <p className="form-error">{error}</p>}<div className="student-form-actions"><button className="button primary">ثبت مدرس</button></div></form></section>}<section className="panel student-panel"><div className="student-list">{instructors.length ? instructors.map((instructor) => <article key={instructor.id}><span className="student-avatar adult other">🧑🏻</span><div><strong>{instructor.firstName} {instructor.lastName}</strong><small>{instructor.mobile ?? "بدون شماره تماس"}</small></div><span className="status-pill">فعال</span></article>) : <p className="empty-state">هنوز مدرسی ثبت نشده است.</p>}</div></section></>;
}

function InstructorWorkspace({ sessions }: { sessions: ClassSessionSummary[] }) { return <AttendanceManagement sessions={sessions} teacherMode />; }

function AttendanceManagement({ sessions, teacherMode = false }: { sessions: ClassSessionSummary[]; teacherMode?: boolean }) {
  const [sessionId, setSessionId] = useState(sessions[0]?.id ?? ""); const [entries, setEntries] = useState<AttendanceEntry[]>([]); const [error, setError] = useState(""); const [notes, setNotes] = useState<Record<string, string>>({}); const [saving, setSaving] = useState("");
  useEffect(() => { if (!sessionId && sessions[0]) setSessionId(sessions[0].id); }, [sessionId, sessions]);
  useEffect(() => { if (!sessionId) { setEntries([]); return; } setError(""); fetch(`${API}/admin/class-sessions/${sessionId}/attendance`, { credentials: "include" }).then(async (response) => { const value = await response.json(); if (!response.ok) throw new Error(value.message ?? "دریافت فهرست حضور و غیاب انجام نشد."); setEntries(value as AttendanceEntry[]); }).catch((value: Error) => setError(value.message)); }, [sessionId]);
  async function record(entry: AttendanceEntry, status: AttendanceEntry["status"]) { if (!status) return; setSaving(entry.enrollmentId); setError(""); try { const response = await fetch(`${API}/admin/class-sessions/${sessionId}/attendance/${entry.enrollmentId}`, { method: "PUT", credentials: "include", headers: { "content-type": "application/json" }, body: JSON.stringify({ status, note: notes[entry.enrollmentId] ?? "" }) }); const value = await response.json(); if (!response.ok) throw new Error(value.message ?? "ثبت حضور و غیاب انجام نشد."); setEntries((current) => current.map((item) => item.enrollmentId === entry.enrollmentId ? value as AttendanceEntry : item)); } catch (value) { setError((value as Error).message); } finally { setSaving(""); } }
  const selectedSession = sessions.find((session) => session.id === sessionId); const marked = entries.filter((entry) => entry.status).length; const present = entries.filter((entry) => entry.status === "present").length;
  return <><header><div><span className="mobile-brand">{teacherMode ? "پنل مدرس" : "مدیریت آموزشگاه"}</span><h1>{teacherMode ? "حضور و غیاب کلاس‌ها" : "حضور و غیاب"}</h1><p>{teacherMode ? "جلسه‌های اختصاص‌یافته به شما و ثبت سریع حضور زبان‌آموزان." : "ثبت وضعیت حضور زبان‌آموزان هر جلسه."}</p></div></header><section className="panel attendance-panel"><div className="attendance-toolbar"><label>جلسه<select value={sessionId} onChange={(event) => setSessionId(event.target.value)}><option value="">انتخاب جلسه</option>{sessions.map((session) => <option key={session.id} value={session.id}>{session.classCode} · {formatIranDateTime(session.startsAt)}</option>)}</select></label>{selectedSession && <div className="attendance-summary"><strong>{present.toLocaleString("fa-IR")} حاضر</strong><span>{marked.toLocaleString("fa-IR")} از {entries.length.toLocaleString("fa-IR")} ثبت شده</span></div>}</div>{error && <p className="form-error">{error}</p>}{sessionId && <div className="attendance-list">{entries.length ? entries.map((entry) => <article key={entry.enrollmentId}><div><strong>{entry.firstName} {entry.lastName}</strong><small>{entry.studentNumber}</small></div><input placeholder="یادداشت اختیاری" value={notes[entry.enrollmentId] ?? entry.note ?? ""} onChange={(event) => setNotes((current) => ({ ...current, [entry.enrollmentId]: event.target.value }))} /><div className="attendance-actions"><button className={entry.status === "present" ? "selected present" : ""} disabled={saving === entry.enrollmentId} onClick={() => void record(entry, "present")}>حاضر</button><button className={entry.status === "late" ? "selected late" : ""} disabled={saving === entry.enrollmentId} onClick={() => void record(entry, "late")}>با تأخیر</button><button className={entry.status === "absent" ? "selected absent" : ""} disabled={saving === entry.enrollmentId} onClick={() => void record(entry, "absent")}>غایب</button><button className={entry.status === "excused" ? "selected excused" : ""} disabled={saving === entry.enrollmentId} onClick={() => void record(entry, "excused")}>موجه</button></div></article>) : <p className="empty-state">برای این جلسه زبان‌آموز فعالی ثبت نشده است.</p>}</div>}{!sessions.length && <p className="empty-state">هنوز جلسه‌ای برای ثبت حضور و غیاب وجود ندارد.</p>}</section></>;
}

function FinanceManagement({ students, invoices, gateway, onCreate, onPayment }: { students: StudentSummary[]; invoices: InvoiceSummary[]; gateway?: PaymentGatewayStatus; onCreate: (input: Record<string, unknown>) => Promise<void>; onPayment: (invoiceId: string, amountRials: number) => Promise<void> }) {
  const [open, setOpen] = useState(false); const [studentId, setStudentId] = useState(students[0]?.id ?? ""); const [amount, setAmount] = useState(""); const [dueOn, setDueOn] = useState(""); const [paymentAmounts, setPaymentAmounts] = useState<Record<string, string>>({}); const [error, setError] = useState(""); const outstanding = invoices.reduce((sum, invoice) => sum + invoice.balanceRials, 0);
  return <><header><div><span className="mobile-brand">مدیریت آموزشگاه</span><h1>مالی و شهریه</h1><p>صدور فاکتور، پیگیری مانده و ثبت پرداخت‌ها.</p></div><button className="button primary" onClick={() => setOpen(true)}>+ صدور فاکتور</button></header>{gateway && <p className={`gateway-status ${gateway.configured ? "configured" : "manual"}`}>درگاه پرداخت: {gateway.label} · {gateway.configured ? "آماده استفاده" : "ثبت پرداخت دستی فعال است"}</p>}{open && <section className="panel student-form finance-form"><div className="panel-title"><div><h2>صدور فاکتور جدید</h2><p>مبالغ به ریال ثبت می‌شوند.</p></div><button onClick={() => setOpen(false)}>بستن</button></div><form onSubmit={(event) => { event.preventDefault(); setError(""); void onCreate({ studentId, totalRials: Number(amount), dueOn: dueOn ? jalaliToGregorianClient(dueOn) : undefined }).then(() => { setOpen(false); setAmount(""); setDueOn(""); }).catch((value: Error) => setError(value.message)); }}><div className="student-form-grid"><label>زبان‌آموز<select required value={studentId} onChange={(event) => setStudentId(event.target.value)}>{students.filter((student) => student.status !== "inactive").map((student) => <option key={student.id} value={student.id}>{student.firstName} {student.lastName} · {student.studentNumber}</option>)}</select></label><label>مبلغ (ریال)<input required inputMode="numeric" dir="ltr" value={formatRials(amount)} onChange={(event) => setAmount(event.target.value.replace(/[^0-9]/g, ""))} placeholder="50,000,000" /></label><JalaliDatePicker label="تاریخ سررسید" value={dueOn} minValue={jalaliTodayString()} onChange={setDueOn} /></div>{error && <p className="form-error">{error}</p>}<div className="student-form-actions"><button type="button" className="button secondary" onClick={() => setOpen(false)}>انصراف</button><button className="button primary">صدور فاکتور</button></div></form></section>}<section className="stats-grid finance-stats"><article><span>مانده کل</span><strong>{outstanding.toLocaleString("fa-IR")}</strong><small>ریال</small></article><article><span>فاکتورهای باز</span><strong>{invoices.filter((invoice) => invoice.balanceRials > 0).length.toLocaleString("fa-IR")}</strong><small>فاکتور</small></article><article><span>تسویه‌شده</span><strong>{invoices.filter((invoice) => invoice.status === "paid").length.toLocaleString("fa-IR")}</strong><small>فاکتور</small></article></section><section className="panel student-panel"><div className="panel-title"><div><h2>فاکتورها</h2><p>{invoices.length.toLocaleString("fa-IR")} فاکتور ثبت شده</p></div><button className="button secondary export-button" onClick={() => downloadInvoicesCsv(invoices)}>خروجی CSV</button></div><div className="invoice-list">{invoices.length ? invoices.map((invoice) => <article key={invoice.id}><div><strong>{invoice.studentName}</strong><small>{invoice.number}{invoice.dueOn ? " · سررسید " + invoice.dueOn : ""}</small></div><div><small>مبلغ کل</small><strong>{invoice.totalRials.toLocaleString("fa-IR")} ریال</strong></div><div><small>مانده</small><strong className={invoice.balanceRials ? "invoice-balance" : "invoice-paid"}>{invoice.balanceRials.toLocaleString("fa-IR")} ریال</strong></div><span className="status-pill">{invoice.status === "paid" ? "تسویه‌شده" : invoice.status === "partial" ? "پرداخت ناقص" : "باز"}</span><button className="invoice-print" onClick={() => printInvoice(invoice)}>چاپ</button>{invoice.balanceRials > 0 && <div className="invoice-payment"><input inputMode="numeric" dir="ltr" placeholder="مبلغ پرداخت" value={formatRials(paymentAmounts[invoice.id] ?? "")} onChange={(event) => setPaymentAmounts((current) => ({ ...current, [invoice.id]: event.target.value.replace(/[^0-9]/g, "") }))} /><button className="button secondary" onClick={() => { const value = Number(paymentAmounts[invoice.id]); if (!value) return; void onPayment(invoice.id, value).then(() => setPaymentAmounts((current) => ({ ...current, [invoice.id]: "" }))).catch((value: Error) => setError(value.message)); }}>ثبت پرداخت</button></div>}</article>) : <p className="empty-state">هنوز فاکتوری صادر نشده است.</p>}</div>{error && <p className="form-error">{error}</p>}</section></>;
}

function ReportsManagement({ report }: { report?: ReportOverview }) {
  if (!report) return <section className="panel"><p className="empty-state">در حال دریافت گزارش‌ها...</p></section>;
  const attendanceRows = [{ label: "حاضر", value: report.attendance.present, className: "present" }, { label: "غایب", value: report.attendance.absent, className: "absent" }, { label: "با تأخیر", value: report.attendance.late, className: "late" }, { label: "موجه", value: report.attendance.excused, className: "excused" }];
  const totalAttendance = report.attendance.present + report.attendance.absent + report.attendance.late + report.attendance.excused;
  return <><header><div><span className="mobile-brand">مدیریت آموزشگاه</span><h1>گزارش‌ها</h1><p>نمای کلی از عملکرد آموزشگاه و وضعیت مالی.</p></div><small className="report-updated">به‌روزرسانی: {formatIranDateTime(report.generatedAt)}</small></header><section className="stats-grid report-stats"><article><span>زبان‌آموز فعال</span><strong>{report.activeStudents.toLocaleString("fa-IR")}</strong><small>در آموزشگاه</small></article><article><span>کلاس فعال</span><strong>{report.activeClasses.toLocaleString("fa-IR")}</strong><small>کلاس</small></article><article><span>جلسه پیش‌رو</span><strong>{report.scheduledSessions.toLocaleString("fa-IR")}</strong><small>جلسه</small></article><article><span>مانده دریافتنی</span><strong>{report.outstandingRials.toLocaleString("fa-IR")}</strong><small>ریال</small></article></section><section className="dashboard-grid report-grid"><section className="panel"><div className="panel-title"><div><h2>حضور و غیاب</h2><p>نرخ حضور ثبت‌شده: {report.attendance.rate.toLocaleString("fa-IR")}٪</p></div><strong className="report-rate">{report.attendance.rate.toLocaleString("fa-IR")}٪</strong></div><div className="report-bars">{attendanceRows.map((row) => <div key={row.label}><span>{row.label}</span><i><b className={row.className} style={{ width: (totalAttendance ? Math.max(4, row.value / totalAttendance * 100) : 0) + "%" }} /></i><strong>{row.value.toLocaleString("fa-IR")}</strong></div>)}</div></section><section className="panel report-note"><h2>خلاصه مدیریتی</h2><p>{report.outstandingRials > 0 ? "بخشی از شهریه‌ها هنوز مانده دارند و می‌توان از بخش مالی پیگیری کرد." : "در حال حاضر مانده‌ای برای پیگیری مالی ثبت نشده است."}</p><p>{report.attendance.rate >= 80 ? "نرخ حضور وضعیت مناسبی دارد." : "نرخ حضور نیاز به پیگیری آموزشی دارد."}</p></section></section></>;
}

function ClassManagement({ students, classes, options, formOpen, setFormOpen, onCreate, sessions, sessionFormOpen, setSessionFormOpen, onCreateSession, onUpdateSession, onCancelSession }: { students: StudentSummary[]; classes: ClassSummary[]; options: ClassOptions; formOpen: boolean; setFormOpen: (value: boolean) => void; onCreate: (input: Record<string, unknown>) => Promise<void>; sessions: ClassSessionSummary[]; sessionFormOpen: boolean; setSessionFormOpen: (value: boolean) => void; onCreateSession: (input: Record<string, unknown>) => Promise<void>; onUpdateSession: (id: string, input: Record<string, unknown>) => Promise<void>; onCancelSession: (id: string) => Promise<void> }) {
  const [sessionDraft, setSessionDraft] = useState<{ date?: string; time?: string; session?: ClassSessionSummary }>({}); const openAt = (date: string, time = "09:00") => { setSessionDraft({ date, time }); setSessionFormOpen(true); }; const openSession = (session: ClassSessionSummary) => { setSessionDraft({ date: iranJalaliDate(new Date(session.startsAt)), time: iranClock(session.startsAt), session }); setSessionFormOpen(true); }; const [selectedClass, setSelectedClass] = useState<ClassSummary | null>(null); const [enrollments, setEnrollments] = useState<ClassEnrollmentSummary[]>([]); const [enrollmentError, setEnrollmentError] = useState("");
  useEffect(() => { if (!selectedClass) { setEnrollments([]); return; } setEnrollmentError(""); fetch(`${API}/admin/classes/${selectedClass.id}/enrollments`, { credentials: "include" }).then(async (response) => { const value = await response.json(); if (!response.ok) throw new Error(value.message ?? "دریافت فهرست کلاس انجام نشد."); setEnrollments(value as ClassEnrollmentSummary[]); }).catch((error: Error) => setEnrollmentError(error.message)); }, [selectedClass]);
  async function enrollStudent(studentId: string) { if (!selectedClass) return; const response = await fetch(`${API}/admin/classes/${selectedClass.id}/enrollments`, { method: "POST", credentials: "include", headers: { "content-type": "application/json" }, body: JSON.stringify({ studentId }) }); const value = await response.json(); if (!response.ok) throw new Error(value.message ?? "افزودن زبان‌آموز انجام نشد."); setEnrollments((current) => [...current, value as ClassEnrollmentSummary].sort((a, b) => a.lastName.localeCompare(b.lastName))); }
  async function updateEnrollment(id: string, status: ClassEnrollmentSummary["status"]) { const response = await fetch(`${API}/admin/enrollments/${id}`, { method: "PATCH", credentials: "include", headers: { "content-type": "application/json" }, body: JSON.stringify({ status }) }); const value = await response.json(); if (!response.ok) throw new Error(value.message ?? "به‌روزرسانی وضعیت انجام نشد."); setEnrollments((current) => current.map((item) => item.id === id ? value as ClassEnrollmentSummary : item)); }
  return <><header><div><span className="mobile-brand">برنامه آموزشگاه</span><h1>کلاس‌ها و برنامه</h1><p>نمایش کلاس‌های تعریف‌شده و وضعیت برگزاری آن‌ها.</p></div><div className="dashboard-actions"><button className="button secondary" onClick={() => { setSessionDraft({}); setSessionFormOpen(true); }}>+ جلسه جدید</button><button className="button primary" onClick={() => setFormOpen(true)}>+ ساخت کلاس</button></div></header>{formOpen && <ClassForm options={options} onCancel={() => setFormOpen(false)} onCreate={onCreate} />}{sessionFormOpen && <SessionForm key={`${sessionDraft.session?.id ?? "new"}-${sessionDraft.date ?? ""}-${sessionDraft.time ?? ""}`} classes={classes} options={options} initialDate={sessionDraft.date} initialTime={sessionDraft.time} initialSession={sessionDraft.session} onCancel={() => setSessionFormOpen(false)} onCreate={onCreateSession} onUpdate={onUpdateSession} onCancelSession={onCancelSession} />}{<CalendarWeek sessions={sessions} onCreateAt={openAt} onOpenSession={openSession} />}{selectedClass && <ClassRoster classItem={selectedClass} students={students} enrollments={enrollments} error={enrollmentError} onClose={() => setSelectedClass(null)} onEnroll={enrollStudent} onStatus={updateEnrollment} />}<section className="panel student-panel"><div className="panel-title"><div><h2>کلاس‌ها</h2><p>{classes.length.toLocaleString("fa-IR")} کلاس ثبت شده · برای مدیریت زبان‌آموزان روی کلاس کلیک کنید</p></div></div><div className="class-list">{classes.length ? classes.map((item) => <article key={item.id} className="class-row-clickable" onClick={() => setSelectedClass(item)}><div className="class-code">{item.code}</div><div><strong>{item.level} · {item.language === "en" ? "انگلیسی" : "آلمانی"}</strong><small>{item.branchName} · {item.roomName ?? "اتاق تعیین نشده"}</small></div><div><small>مدرس</small><strong>{item.instructorName ?? "تعیین نشده"}</strong></div><div><small>ظرفیت</small><strong>{item.capacity.toLocaleString("fa-IR")} نفر</strong></div><span className="status-pill">{item.status === "active" ? "فعال" : item.status}</span></article>) : <p className="empty-state">هنوز کلاسی تعریف نشده است.</p>}</div></section><section className="panel student-panel"><div className="panel-title"><div><h2>جلسه‌های برنامه‌ریزی‌شده</h2><p>{sessions.length.toLocaleString("fa-IR")} جلسه</p></div></div><div className="class-list">{sessions.length ? sessions.map((session) => <article key={session.id}><div className="class-code">{session.classCode}</div><div><strong>{session.level} · {session.language === "en" ? "انگلیسی" : "آلمانی"}</strong><small>{formatIranDateTime(session.startsAt)}</small></div><div><small>مدرس</small><strong>{session.instructorName ?? "تعیین نشده"}</strong></div><div><small>اتاق</small><strong>{session.roomName ?? "آنلاین"}</strong>{session.meetingUrl && <a dir="ltr" className="session-link" href={session.meetingUrl} target="_blank" rel="noreferrer">ورود به جلسه</a>}</div><span className="status-pill">{session.status === "scheduled" ? "برگزار می‌شود" : session.status}</span></article>) : <p className="empty-state">هنوز جلسه‌ای برنامه‌ریزی نشده است.</p>}</div></section></>;
}

function ClassRoster({ classItem, students, enrollments, error, onClose, onEnroll, onStatus }: { classItem: ClassSummary; students: StudentSummary[]; enrollments: ClassEnrollmentSummary[]; error: string; onClose: () => void; onEnroll: (studentId: string) => Promise<void>; onStatus: (id: string, status: ClassEnrollmentSummary["status"]) => Promise<void> }) {
  const [studentId, setStudentId] = useState(""); const [actionError, setActionError] = useState(""); const enrolledIds = new Set(enrollments.map((item) => item.studentId)); const available = students.filter((student) => !enrolledIds.has(student.id) && student.status !== "inactive");
  return <section className="panel class-roster"><div className="panel-title"><div><button className="detail-back" onClick={onClose}>← بازگشت به فهرست کلاس‌ها</button><h2>{classItem.code} · زبان‌آموزان کلاس</h2><p>{enrollments.length.toLocaleString("fa-IR")} از {classItem.capacity.toLocaleString("fa-IR")} نفر ظرفیت</p></div><button onClick={onClose}>بستن</button></div><div className="enrollment-add"><select value={studentId} onChange={(event) => setStudentId(event.target.value)}><option value="">انتخاب زبان‌آموز برای افزودن</option>{available.map((student) => <option key={student.id} value={student.id}>{student.firstName} {student.lastName} · {student.studentNumber}</option>)}</select><button className="button primary" disabled={!studentId || enrollments.length >= classItem.capacity} onClick={() => { setActionError(""); void onEnroll(studentId).then(() => setStudentId("")).catch((value: Error) => setActionError(value.message)); }}>افزودن</button></div>{(error || actionError) && <p className="form-error">{error || actionError}</p>}<div className="enrollment-list">{enrollments.length ? enrollments.map((enrollment) => <article key={enrollment.id}><div className="student-avatar adult other">🧑🏻</div><div><strong>{enrollment.firstName} {enrollment.lastName}</strong><small>{enrollment.studentNumber}{enrollment.mobile ? ` · ${enrollment.mobile}` : ""}</small></div><select value={enrollment.status} onChange={(event) => { void onStatus(enrollment.id, event.target.value as ClassEnrollmentSummary["status"]).catch((value: Error) => setActionError(value.message)); }}><option value="active">فعال</option><option value="pending">در انتظار</option><option value="frozen">متوقف</option><option value="transferred">انتقال‌یافته</option><option value="cancelled">لغوشده</option><option value="completed">تکمیل‌شده</option></select></article>) : <p className="empty-state">هنوز زبان‌آموزی به این کلاس اضافه نشده است.</p>}</div></section>;
}

function CalendarWeek({ sessions, onCreateAt, onOpenSession }: { sessions: ClassSessionSummary[]; onCreateAt: (date: string, time?: string) => void; onOpenSession: (session: ClassSessionSummary) => void }) {
  const [anchor, setAnchor] = useState(() => startIranWeek(new Date())); const [selectedDay, setSelectedDay] = useState(0); const [view, setView] = useState<"week" | "month" | "day">("week"); const [dayViewDate, setDayViewDate] = useState(jalaliTodayString); const days = Array.from({ length: 7 }, (_, index) => new Date(anchor.getTime() + index * 86400000)); const today = iranianToday(); const [monthYear, setMonthYear] = useState(today.year); const [month, setMonth] = useState(today.month);
  const moveMonth = (delta: number) => { const next = month + delta; if (next < 1) { setMonth(12); setMonthYear(monthYear - 1); } else if (next > 12) { setMonth(1); setMonthYear(monthYear + 1); } else setMonth(next); };
  const openDay = (date: string) => { setDayViewDate(date); setView("day"); };
  if (view === "day") return <section className="panel calendar-panel"><div className="panel-title"><div><h2>برنامه روزانه</h2><p>{formatJalaliDate(dayViewDate)} · زمان ایران</p></div><div className="calendar-actions"><button className="button secondary calendar-back" onClick={() => setView("week")}>بازگشت به تقویم</button><button className="button primary" onClick={() => onCreateAt(dayViewDate, "09:00")}>+ جلسه جدید</button></div></div><CalendarDayView date={dayViewDate} sessions={sessions} onCreateAt={onCreateAt} onOpenSession={onOpenSession} /></section>;
  return <section className="panel calendar-panel"><div className="panel-title"><div><h2>{view === "week" ? "تقویم هفتگی" : "تقویم ماهانه"}</h2><p>{view === "week" ? "شنبه تا جمعه · زمان ایران" : `${monthYear}/${month.toString().padStart(2, "0")} · تقویم جلالی`}</p></div><div className="calendar-actions"><div className="calendar-view-toggle"><button className={view === "week" ? "active" : ""} onClick={() => setView("week")}>هفته</button><button className={view === "month" ? "active" : ""} onClick={() => setView("month")}>ماه</button></div>{view === "week" ? <div className="calendar-nav"><button onClick={() => { setAnchor(new Date(anchor.getTime() - 7 * 86400000)); setSelectedDay(0); }}>هفته قبل</button><button onClick={() => { setAnchor(startIranWeek(new Date())); setSelectedDay(0); }}>امروز</button><button onClick={() => { setAnchor(new Date(anchor.getTime() + 7 * 86400000)); setSelectedDay(0); }}>هفته بعد</button></div> : <div className="calendar-nav"><button onClick={() => moveMonth(-1)}>ماه قبل</button><button onClick={() => { setMonthYear(today.year); setMonth(today.month); }}>امروز</button><button onClick={() => moveMonth(1)}>ماه بعد</button></div>}</div></div>{view === "week" ? <><div className="mobile-day-picker">{days.map((day, index) => <button className={index === selectedDay ? "active" : ""} key={iranDateKey(day)} onClick={() => openDay(iranJalaliDate(day))}><strong>{iranWeekday(day)}</strong><small>{iranDateLabel(day)}</small></button>)}</div><div className="calendar-grid">{days.map((day, index) => { const key = iranDateKey(day); const daySessions = sessions.filter((session) => iranDateKey(new Date(session.startsAt)) === key); return <div className={`calendar-day ${index === selectedDay ? "selected" : ""}`} key={key} onClick={() => openDay(iranJalaliDate(day))}><header><strong>{iranWeekday(day)}</strong><small>{iranDateLabel(day)}</small></header><div>{daySessions.map((session) => <article key={session.id} onClick={(event) => { event.stopPropagation(); onOpenSession(session); }}><b>{iranTime(session.startsAt)}</b><span>{session.classCode} · {session.level}</span><small>{session.roomName ?? "آنلاین"}</small></article>)}</div></div>; })}</div></> : <CalendarMonth year={monthYear} month={month} sessions={sessions} onCreateAt={openDay} onOpenSession={onOpenSession} />}</section>;
}

function CalendarMonth({ year, month, sessions, onCreateAt, onOpenSession }: { year: number; month: number; sessions: ClassSessionSummary[]; onCreateAt: (date: string, time?: string) => void; onOpenSession: (session: ClassSessionSummary) => void }) {
  const firstDate = new Date(`${jalaliToGregorianClient(`${year}/${month.toString().padStart(2, "0")}/01`)}T00:00:00+03:30`); const leading = (firstDate.getUTCDay() + 1) % 7; const count = jalaliMonthDays(year, month); const cells = Array.from({ length: leading + count }, (_, index) => index < leading ? null : index - leading + 1); const names = ["شنبه", "یکشنبه", "دوشنبه", "سه‌شنبه", "چهارشنبه", "پنجشنبه", "جمعه"];
  return <div className="month-grid">{names.map((name) => <strong className="month-heading" key={name}>{name}</strong>)}{cells.map((day, index) => { if (!day) return <div className="month-cell empty" key={`empty-${index}`} />; const dateKey = iranDateKey(new Date(`${jalaliToGregorianClient(`${year}/${month.toString().padStart(2, "0")}/${day.toString().padStart(2, "0")}`)}T12:00:00+03:30`)); const daySessions = sessions.filter((session) => iranDateKey(new Date(session.startsAt)) === dateKey); return <div className="month-cell" key={dateKey} onClick={() => onCreateAt(`${year}/${month.toString().padStart(2, "0")}/${day.toString().padStart(2, "0")}`)}><b>{day}</b>{daySessions.map((session) => <article key={session.id} onClick={(event) => { event.stopPropagation(); onOpenSession(session); }}><span>{iranTime(session.startsAt)} · {session.classCode}</span></article>)}</div>; })}</div>;
}

function CalendarDayView({ date, sessions, onCreateAt, onOpenSession }: { date: string; sessions: ClassSessionSummary[]; onCreateAt: (date: string, time?: string) => void; onOpenSession: (session: ClassSessionSummary) => void }) {
  const dayKey = iranDateKey(new Date(`${jalaliToGregorianClient(date)}T12:00:00+03:30`)); const daySessions = sessions.filter((session) => iranDateKey(new Date(session.startsAt)) === dayKey);
  return <div className="day-view"><div className="day-view-label"><span>ساعت</span><small>برای ساخت جلسه، یک بازه را انتخاب کنید</small></div><div className="day-time-grid">{Array.from({ length: 24 }, (_, hour) => { const time = `${hour.toString().padStart(2, "0")}:00`; const hourSessions = daySessions.filter((session) => iranHour(session.startsAt) === hour); return <button type="button" className="day-time-slot" key={time} onClick={() => onCreateAt(date, time)}><time>{time}</time><span className="day-slot-line" />{hourSessions.map((session) => <article key={session.id} onClick={(event) => { event.stopPropagation(); onOpenSession(session); }}><b>{iranTime(session.startsAt)} · {session.classCode}</b><small>{session.level} · {session.roomName ?? "آنلاین"}</small></article>)}</button>; })}</div></div>;
}

function SessionForm({ classes, options, initialDate, initialTime, initialSession, onCancel, onCreate, onUpdate, onCancelSession }: { classes: ClassSummary[]; options: ClassOptions; initialDate?: string; initialTime?: string; initialSession?: ClassSessionSummary; onCancel: () => void; onCreate: (input: Record<string, unknown>) => Promise<void>; onUpdate: (id: string, input: Record<string, unknown>) => Promise<void>; onCancelSession: (id: string) => Promise<void> }) {
  const startsAt = initialDate && initialTime ? `${initialDate} ${initialTime}` : "";
  const endsAt = initialDate && initialTime ? `${initialDate} ${addMinutes(initialTime, 60)}` : "";
  const sessionStarts = initialSession ? `${iranJalaliDate(new Date(initialSession.startsAt))} ${iranClock(initialSession.startsAt)}` : startsAt; const sessionEnds = initialSession ? `${iranJalaliDate(new Date(initialSession.endsAt))} ${iranClock(initialSession.endsAt)}` : endsAt; const editing = Boolean(initialSession);
  const [form, setForm] = useState({ classId: initialSession?.classId ?? classes[0]?.id ?? "", startsAt: sessionStarts, endsAt: sessionEnds, instructorId: initialSession?.instructorId ?? "", roomId: initialSession?.roomId ?? "", recurrenceRule: initialSession?.recurrenceRule ?? "none", occurrences: "1", meetingProvider: initialSession?.meetingProvider ?? "none", meetingUrl: initialSession?.meetingUrl ?? "" }); const [error, setError] = useState(""); const update = (key: keyof typeof form, value: string) => setForm((current) => ({ ...current, [key]: value }));
  async function save() { try { const input = { ...form, occurrences: Number(form.occurrences), startsAt: jalaliTimeToIso(form.startsAt), endsAt: jalaliTimeToIso(form.endsAt) }; if (editing && initialSession) await onUpdate(initialSession.id, input); else await onCreate(input); } catch (value) { setError((value as Error).message); } }
  async function cancelCurrent() { if (!initialSession || !window.confirm("آیا از لغو این جلسه مطمئن هستید؟")) return; try { await onCancelSession(initialSession.id); onCancel(); } catch (value) { setError((value as Error).message); } }
  useEffect(() => { const onKeyDown = (event: KeyboardEvent) => { if (event.key === "Escape") onCancel(); }; document.addEventListener("keydown", onKeyDown); const previousOverflow = document.body.style.overflow; document.body.style.overflow = "hidden"; return () => { document.removeEventListener("keydown", onKeyDown); document.body.style.overflow = previousOverflow; }; }, [onCancel]);
  return <div className="session-modal-backdrop" role="presentation" onMouseDown={(event) => { if (event.target === event.currentTarget) onCancel(); }}><section className="session-modal panel student-form" role="dialog" aria-modal="true" aria-labelledby="session-modal-title" onMouseDown={(event) => event.stopPropagation()}><div className="session-modal-header"><div><span className="kicker">تقویم آموزشگاه</span><h2 id="session-modal-title">{editing ? "ویرایش جلسه" : "جلسه جدید"}</h2><p>زمان، کلاس و جزئیات برگزاری را تنظیم کنید.</p></div><button type="button" className="modal-close" aria-label="بستن پنجره" onClick={onCancel}>×</button></div><form onSubmit={(event) => { event.preventDefault(); void save(); }}><div className="student-form-grid"><label>کلاس<select required value={form.classId} onChange={(event) => update("classId", event.target.value)}>{classes.map((item) => <option key={item.id} value={item.id}>{item.code} · {item.level}</option>)}</select></label><JalaliTimePicker label="شروع" value={form.startsAt} minValue={jalaliTodayString()} onChange={(value) => update("startsAt", value)} /><JalaliTimePicker label="پایان" value={form.endsAt} minValue={jalaliTodayString()} onChange={(value) => update("endsAt", value)} /><label>تکرار<select value={form.recurrenceRule} onChange={(event) => update("recurrenceRule", event.target.value)}><option value="none">فقط همین جلسه</option><option value="weekly">هر هفته</option></select></label>{form.recurrenceRule === "weekly" && <label>تعداد هفته<input type="number" min="1" max="52" value={form.occurrences} onChange={(event) => update("occurrences", event.target.value)} /></label>}<label>مدرس<select value={form.instructorId} onChange={(event) => update("instructorId", event.target.value)}><option value="">تعیین نشده</option>{options.instructors.map((item) => <option key={item.id} value={item.id}>{item.name}</option>)}</select></label><label>اتاق<select value={form.roomId} onChange={(event) => update("roomId", event.target.value)}><option value="">آنلاین / تعیین نشده</option>{options.rooms.map((item) => <option key={item.id} value={item.id}>{item.name}</option>)}</select></label><label>نوع جلسه<select value={form.meetingProvider} onChange={(event) => update("meetingProvider", event.target.value)}><option value="none">بدون لینک آنلاین</option><option value="google_meet">Google Meet</option><option value="skyroom">Skyroom</option><option value="other">سایر</option></select></label>{form.meetingProvider !== "none" && <label>لینک جلسه<input dir="ltr" type="url" placeholder="https://..." value={form.meetingUrl} onChange={(event) => update("meetingUrl", event.target.value)} /></label>}</div>{error && <p className="form-error">{error}</p>}<div className="student-form-actions">{editing && <button type="button" className="button danger" onClick={() => void cancelCurrent()}>لغو جلسه</button>}<button type="button" className="button secondary" onClick={onCancel}>انصراف</button><button className="button primary">{editing ? "ذخیره تغییرات" : "ثبت جلسه"}</button></div></form></section></div>;
}

function ClassForm({ options, onCancel, onCreate }: { options: ClassOptions; onCancel: () => void; onCreate: (input: Record<string, unknown>) => Promise<void> }) {
  const [form, setForm] = useState({ code: "", branchId: options.branches[0]?.id ?? "", termId: options.terms[0]?.id ?? "", language: "en", levelId: options.levels.find((item) => item.language === "en")?.id ?? "", instructorId: "", roomId: "", capacity: "12", feeRials: "0", classType: "in_person" }); const [error, setError] = useState(""); const update = (key: keyof typeof form, value: string) => setForm((current) => ({ ...current, [key]: value })); const levels = options.levels.filter((item) => item.language === form.language);
  return <section className="panel student-form"><div className="panel-title"><h2>ساخت کلاس جدید</h2><button onClick={onCancel}>بستن</button></div><form onSubmit={(event) => { event.preventDefault(); void onCreate({ ...form, capacity: Number(form.capacity), feeRials: Number(form.feeRials) }).catch((value: Error) => setError(value.message)); }}><div className="student-form-grid"><label>کد کلاس<input required dir="ltr" placeholder="EN-A2-01" value={form.code} onChange={(event) => update("code", event.target.value)} /></label><label>زبان<select value={form.language} onChange={(event) => { const language = event.target.value; update("language", language); update("levelId", options.levels.find((item) => item.language === language)?.id ?? ""); }}><option value="en">انگلیسی</option><option value="de">آلمانی</option></select></label><label>شعبه<select value={form.branchId} onChange={(event) => update("branchId", event.target.value)}>{options.branches.map((item) => <option key={item.id} value={item.id}>{item.name}</option>)}</select></label><label>ترم<select value={form.termId} onChange={(event) => update("termId", event.target.value)}>{options.terms.map((item) => <option key={item.id} value={item.id}>{item.name}</option>)}</select></label><label>سطح<select value={form.levelId} onChange={(event) => update("levelId", event.target.value)}>{levels.map((item) => <option key={item.id} value={item.id}>{item.label}</option>)}</select></label><label>نوع کلاس<select value={form.classType} onChange={(event) => update("classType", event.target.value)}><option value="in_person">حضوری</option><option value="online">آنلاین</option><option value="hybrid">ترکیبی</option></select></label><label>مدرس<select value={form.instructorId} onChange={(event) => update("instructorId", event.target.value)}><option value="">تعیین نشده</option>{options.instructors.map((item) => <option key={item.id} value={item.id}>{item.name}</option>)}</select></label><label>اتاق<select value={form.roomId} onChange={(event) => update("roomId", event.target.value)}><option value="">تعیین نشده</option>{options.rooms.filter((item) => !form.branchId || item.branchId === form.branchId).map((item) => <option key={item.id} value={item.id}>{item.name}</option>)}</select></label><label>ظرفیت<input type="number" min="1" value={form.capacity} onChange={(event) => update("capacity", event.target.value)} /></label><label>شهریه (ریال)<input inputMode="numeric" dir="ltr" value={formatRials(form.feeRials)} onChange={(event) => update("feeRials", event.target.value.replace(/[^0-9]/g, ""))} placeholder="50,000,000" /></label></div>{error && <p className="form-error">{error}</p>}<div className="student-form-actions"><button className="button secondary" type="button" onClick={onCancel}>انصراف</button><button className="button primary">ساخت کلاس</button></div></form></section>;
}

function formatRials(value: string) { return value ? Number(value).toLocaleString("en-US") : ""; }
function downloadInvoicesCsv(invoices: InvoiceSummary[]) { const header = ["شماره فاکتور", "زبان‌آموز", "مبلغ کل (ریال)", "مانده (ریال)", "وضعیت", "سررسید"]; const rows = invoices.map((invoice) => [invoice.number, invoice.studentName, invoice.totalRials, invoice.balanceRials, invoice.status, invoice.dueOn ?? ""]); const csv = [header, ...rows].map((row) => row.map((value) => `"${String(value).replace(/"/g, '""')}"`).join(",")).join("\n"); const blob = new Blob(["\uFEFF" + csv], { type: "text/csv;charset=utf-8" }); const url = URL.createObjectURL(blob); const link = document.createElement("a"); link.href = url; link.download = `zabankadeh-invoices-${new Date().toISOString().slice(0, 10)}.csv`; link.click(); URL.revokeObjectURL(url); }

function isInstructorOnly(roles?: Array<{ role: string }>) { const values = roles?.map(({ role }) => role) ?? []; return values.includes("instructor") && !values.some((role) => ["owner", "branch_manager", "registrar", "academic_supervisor"].includes(role)); }

function StudentDetail({ student, onClose, onUpdate }: { student: StudentSummary; onClose: () => void; onUpdate: (id: string, input: Record<string, unknown>) => Promise<void> }) {
  const detail = student as StudentSummary & { email?: string | null; nationalId?: string | null; guardianRelationship?: string | null };
  const [form, setForm] = useState({ firstName: student.firstName, lastName: student.lastName, mobile: student.mobile ?? "", email: detail.email ?? "", birthDate: student.birthDateJalali ?? "", gender: student.gender ?? "other", status: student.status, guardianName: student.guardianName ?? "", guardianMobile: student.guardianMobile ?? "", guardianRelationship: detail.guardianRelationship ?? "مادر" });
  const [error, setError] = useState("");
  const update = (key: keyof typeof form, value: string) => setForm((current) => ({ ...current, [key]: value }));
  return <><header><div><button className="detail-back" onClick={onClose}>← بازگشت به فهرست</button><h1>پرونده زبان‌آموز</h1><p>{student.studentNumber}</p></div></header><section className="panel student-form student-detail"><div className="student-detail-heading"><StudentAvatar student={{ ...student, gender: form.gender as StudentSummary["gender"], birthDateJalali: form.birthDate }} /><div><h2>{student.firstName} {student.lastName}</h2><p>تاریخ عضویت: {student.joinedAt}</p></div></div><form onSubmit={(event) => { event.preventDefault(); setError(""); const [guardianFirstName = "", ...rest] = form.guardianName.split(" "); void onUpdate(student.id, { firstName: form.firstName, lastName: form.lastName, mobile: form.mobile, email: form.email, birthDate: form.birthDate, gender: form.gender, status: form.status, guardian: form.guardianName || form.guardianMobile ? { firstName: guardianFirstName, lastName: rest.join(" "), mobile: form.guardianMobile, relationship: form.guardianRelationship } : undefined }).catch((value: Error) => setError(value.message)); }}><div className="student-form-grid"><label>نام<input required value={form.firstName} onChange={(event) => update("firstName", event.target.value)} /></label><label>نام خانوادگی<input required value={form.lastName} onChange={(event) => update("lastName", event.target.value)} /></label><label>جنسیت<select value={form.gender} onChange={(event) => update("gender", event.target.value)}><option value="female">دختر / زن</option><option value="male">پسر / مرد</option><option value="other">سایر</option></select></label><JalaliDatePicker label="تاریخ تولد" value={form.birthDate} maxValue={jalaliTodayString()} onChange={(value) => update("birthDate", value)} /><label>شماره موبایل<input value={form.mobile} onChange={(event) => update("mobile", event.target.value)} /></label><label>ایمیل<input type="email" value={form.email} onChange={(event) => update("email", event.target.value)} /></label><label>وضعیت<select value={form.status} onChange={(event) => update("status", event.target.value)}><option value="active">فعال</option><option value="lead">سرنخ</option><option value="frozen">متوقف</option><option value="inactive">غیرفعال</option></select></label><label>نام کامل ولی<input value={form.guardianName} onChange={(event) => update("guardianName", event.target.value)} /></label><label>موبایل ولی<input value={form.guardianMobile} onChange={(event) => update("guardianMobile", event.target.value)} /></label><label>نسبت ولی<input value={form.guardianRelationship} onChange={(event) => update("guardianRelationship", event.target.value)} /></label></div>{error && <p className="form-error">{error}</p>}<div className="student-form-actions"><button className="button primary">ذخیره تغییرات</button></div></form></section></>;
}

