  const [form, setForm] = useState({ firstName: "", lastName: "", mobile: "", email: "", birthDate: "", gender: "female", guardianFirstName: "", guardianLastName: "", guardianMobile: "", relationship: "مادر" });
  const [error, setError] = useState("");
  const update = (key: keyof typeof form, value: string) => setForm((current) => ({ ...current, [key]: value }));
  return <section className="panel student-form"><div className="panel-title"><div><h2>ثبت زبان‌آموز جدید</h2><p>اطلاعات پایه و ولی را وارد کنید.</p></div><button onClick={onCancel}>بستن</button></div><form onSubmit={(event) => { event.preventDefault(); setError(""); void onCreate({ firstName: form.firstName, lastName: form.lastName, mobile: form.mobile, email: form.email, birthDate: form.birthDate, gender: form.gender, guardian: form.guardianFirstName || form.guardianLastName || form.guardianMobile ? { firstName: form.guardianFirstName, lastName: form.guardianLastName, mobile: form.guardianMobile, relationship: form.relationship } : undefined }).catch((value: Error) => setError(value.message)); }}><div className="student-form-grid"><label>نام<input required value={form.firstName} onChange={(event) => update("firstName", event.target.value)} /></label><label>نام خانوادگی<input required value={form.lastName} onChange={(event) => update("lastName", event.target.value)} /></label><label>جنسیت<select value={form.gender} onChange={(event) => update("gender", event.target.value)}><option value="female">دختر / زن</option><option value="male">پسر / مرد</option><option value="other">سایر</option></select></label><JalaliDatePicker label="تاریخ تولد" value={form.birthDate} maxValue={jalaliTodayString()} onChange={(value) => update("birthDate", value)} /><label>شماره موبایل<input inputMode="tel" value={form.mobile} onChange={(event) => update("mobile", event.target.value)} /></label><label>ایمیل<input type="email" value={form.email} onChange={(event) => update("email", event.target.value)} /></label><label>نام ولی<input value={form.guardianFirstName} onChange={(event) => update("guardianFirstName", event.target.value)} /></label><label>نام خانوادگی ولی<input value={form.guardianLastName} onChange={(event) => update("guardianLastName", event.target.value)} /></label><label>موبایل ولی<input inputMode="tel" value={form.guardianMobile} onChange={(event) => update("guardianMobile", event.target.value)} /></label><label>نسبت<input value={form.relationship} onChange={(event) => update("relationship", event.target.value)} /></label></div>{error && <p className="form-error">{error}</p>}<div className="student-form-actions"><button type="button" className="button secondary" onClick={onCancel}>انصراف</button><button className="button primary">ثبت زبان‌آموز</button></div></form></section>;
