function StudentAvatar({ student }: { student: StudentSummary }) {
  const age = student.birthDateJalali ? jalaliAge(student.birthDateJalali) : 18;
  const child = age < 13;
  const emoji = child ? (student.gender === "male" ? "👦" : student.gender === "female" ? "👧" : "🧒") : student.gender === "male" ? "👨🏻" : student.gender === "female" ? "👩🏻" : "🧑🏻";
  return <span className={`student-avatar ${child ? "child" : "adult"} ${student.gender ?? "other"}`} aria-label={child ? "آواتار کودک" : "آواتار بزرگسال"}>{emoji}</span>;
}

function JalaliDatePicker({ label, value, minValue, maxValue, onChange }: { label: string; value: string; minValue?: string; maxValue?: string; onChange: (value: string) => void }) {
  const [yearText = "", monthText = "", dayText = ""] = value.split("/"); const currentYear = iranianToday().year; const year = Number(yearText) || currentYear; const month = Number(monthText) || 0; const day = Number(dayText) || 0; const minYear = minValue ? Number(minValue.split("/")[0]) : currentYear - 100; const maxYear = maxValue ? Number(maxValue.split("/")[0]) : currentYear + 3; const days = month ? jalaliMonthDays(year, month) : 31;
  const setPart = (part: "year" | "month" | "day", next: string) => { const nextYear = part === "year" ? next : yearText; const nextMonth = part === "month" ? next : monthText; const nextDay = part === "day" ? next : dayText; onChange(nextYear && nextMonth && nextDay ? `${nextYear}/${nextMonth.padStart(2, "0")}/${nextDay.padStart(2, "0")}` : `${nextYear}/${nextMonth}/${nextDay}`); };
  return <label className="jalali-picker">{label}<span><select aria-label={`${label} سال`} value={yearText} onChange={(event) => setPart("year", event.target.value)}><option value="">سال</option>{Array.from({ length: maxYear - minYear + 1 }, (_, index) => maxYear - index).map((item) => <option key={item} value={item}>{item}</option>)}</select><select aria-label={`${label} ماه`} value={monthText} onChange={(event) => setPart("month", event.target.value)}><option value="">ماه</option>{Array.from({ length: 12 }, (_, index) => index + 1).map((item) => <option key={item} value={item}>{item.toString().padStart(2, "0")}</option>)}</select><select aria-label={`${label} روز`} value={dayText} onChange={(event) => updateConstrainedDay(event.target.value, setPart, year, month, minValue, maxValue)}><option value="">روز</option>{Array.from({ length: days }, (_, index) => index + 1).map((item) => <option key={item} value={item}>{item.toString().padStart(2, "0")}</option>)}</select></span></label>;
}

function JalaliTimePicker({ label, value, minValue, onChange }: { label: string; value: string; minValue?: string; onChange: (value: string) => void }) {
  const [date = "", time = ""] = value.split(" ");
  return <div className="jalali-time-picker"><JalaliDatePicker label={label} value={date} minValue={minValue} onChange={(next) => onChange(`${next} ${time}`.trim())} /><label>ساعت<input required dir="ltr" type="time" value={time} onChange={(event) => onChange(`${date} ${event.target.value}`.trim())} /></label></div>;
}

function iranianToday() { const parts = new Intl.DateTimeFormat("en-US-u-ca-persian-nu-latn", { timeZone: "Asia/Tehran", year: "numeric", month: "numeric", day: "numeric" }).formatToParts(new Date()); return { year: Number(parts.find((part) => part.type === "year")?.value), month: Number(parts.find((part) => part.type === "month")?.value), day: Number(parts.find((part) => part.type === "day")?.value) }; }
function jalaliTodayString() { const today = iranianToday(); return `${today.year}/${today.month.toString().padStart(2, "0")}/${today.day.toString().padStart(2, "0")}`; }
function updateConstrainedDay(value: string, setPart: (part: "year" | "month" | "day", value: string) => void, year: number, month: number, minValue?: string, maxValue?: string) { const candidate = `${year}/${month.toString().padStart(2, "0")}/${value.padStart(2, "0")}`; if ((!minValue || candidate >= minValue) && (!maxValue || candidate <= maxValue)) setPart("day", value); }
function jalaliMonthDays(year: number, month: number) { return month <= 6 ? 31 : month <= 11 ? 30 : jalaliLeap(year) ? 30 : 29; }
function jalaliLeap(year: number) { return ((year + 38) * 682) % 2816 < 682; }
function jalaliTimeToIso(value: string) { const [date, time] = value.split(" "); if (!date || !time) throw new Error("تاریخ و ساعت جلسه را کامل کنید."); return `${jalaliToGregorianClient(date)}T${time}:00+03:30`; }
function formatIranDateTime(value: string) { return new Intl.DateTimeFormat("fa-IR-u-ca-persian-nu-latn", { timeZone: "Asia/Tehran", dateStyle: "medium", timeStyle: "short" }).format(new Date(value)); }
function formatJalaliDate(value: string) { return new Intl.DateTimeFormat("fa-IR-u-ca-persian-nu-latn", { timeZone: "Asia/Tehran", dateStyle: "full" }).format(new Date(`${jalaliToGregorianClient(value)}T12:00:00+03:30`)); }
function addMinutes(value: string, minutes: number) { const [hours, mins] = value.split(":").map(Number); const total = hours * 60 + mins + minutes; return `${String(Math.floor(total / 60) % 24).padStart(2, "0")}:${String(total % 60).padStart(2, "0")}`; }
function iranJalaliDate(value: Date) { const parts = new Intl.DateTimeFormat("en-US-u-ca-persian-nu-latn", { timeZone: "Asia/Tehran", year: "numeric", month: "2-digit", day: "2-digit" }).formatToParts(value); const get = (type: Intl.DateTimeFormatPartTypes) => parts.find((part) => part.type === type)?.value ?? ""; return `${get("year")}/${get("month")}/${get("day")}`; }
function iranDateKey(value: Date) { return new Intl.DateTimeFormat("en-CA", { timeZone: "Asia/Tehran", year: "numeric", month: "2-digit", day: "2-digit" }).format(value); }
function startIranWeek(value: Date) { const day = Number(new Intl.DateTimeFormat("en-US", { timeZone: "Asia/Tehran", weekday: "short" }).formatToParts(value).find((part) => part.type === "weekday")?.value === "Sat" ? 0 : value.getDay() + 1); const result = new Date(value); result.setDate(value.getDate() - day); result.setHours(0, 0, 0, 0); return result; }
function iranWeekday(value: Date) { return new Intl.DateTimeFormat("fa-IR", { timeZone: "Asia/Tehran", weekday: "short" }).format(value); }
function iranDateLabel(value: Date) { return new Intl.DateTimeFormat("fa-IR-u-ca-persian-nu-latn", { timeZone: "Asia/Tehran", month: "numeric", day: "numeric" }).format(value); }
function iranTime(value: string) { return new Intl.DateTimeFormat("fa-IR-u-ca-persian-nu-latn", { timeZone: "Asia/Tehran", hour: "2-digit", minute: "2-digit" }).format(new Date(value)); }
function iranClock(value: string) { const parts = new Intl.DateTimeFormat("en-US", { timeZone: "Asia/Tehran", hour: "2-digit", minute: "2-digit", hour12: false }).formatToParts(new Date(value)); return `${parts.find((part) => part.type === "hour")?.value ?? "00"}:${parts.find((part) => part.type === "minute")?.value ?? "00"}`; }
function iranHour(value: string) { return Number(new Intl.DateTimeFormat("en-US", { timeZone: "Asia/Tehran", hour: "2-digit", hour12: false }).format(new Date(value))) % 24; }
function jalaliToGregorianClient(value: string) { const [jyValue, jm, jd] = value.split("/").map(Number); let jy = jyValue - 979; let gy = 1600 + 400 * Math.floor(jy / 146097); jy %= 146097; if (jy >= 36525) { gy += 100 * Math.floor(--jy / 36524); jy %= 36524; if (jy >= 365) jy++; } gy += 4 * Math.floor(jy / 1461); jy %= 1461; if (jy >= 366) { gy += Math.floor((jy - 1) / 365); jy = (jy - 1) % 365; } const days = [0,31,59,90,120,151,181,212,243,273,304,334]; const day = 80 + jd + (jm > 1 ? days[jm - 1] : 0) + 365 * jy + Math.floor(jy / 4) - Math.floor(jy / 100); gy += Math.floor(day / 365); const doy = day % 365; const leap = (gy % 4 === 0 && gy % 100 !== 0) || gy % 400 === 0; const monthDays = [31, leap ? 29 : 28, 31,30,31,30,31,31,30,31,30,31]; let gm = 0; let remaining = doy; while (remaining >= monthDays[gm]) remaining -= monthDays[gm++]; return `${gy.toString().padStart(4, "0")}-${(gm + 1).toString().padStart(2, "0")}-${(remaining + 1).toString().padStart(2, "0")}`; }

function AssessmentManagement({ attempts, onOverride, onRegister }: { attempts: AssessmentAttemptSummary[]; onOverride: (id: string, band: string, reason: string) => Promise<void>; onRegister: (id: string) => Promise<void> }) {
  const [drafts, setDrafts] = useState<Record<string, { band: string; reason: string }>>({});
  const [saving, setSaving] = useState("");
  const [error, setError] = useState("");
  const bands = ["pre-a1", "a1", "a2", "b1", "b2", "c1"];
  const updateDraft = (attempt: AssessmentAttemptSummary, field: "band" | "reason", value: string) => setDrafts((current) => ({ ...current, [attempt.id]: { band: current[attempt.id]?.band ?? attempt.overrideBand ?? attempt.recommendedBand ?? "", reason: current[attempt.id]?.reason ?? attempt.overrideReason ?? "", [field]: value } }));
  async function save(attempt: AssessmentAttemptSummary) { const draft = drafts[attempt.id] ?? { band: attempt.overrideBand ?? attempt.recommendedBand ?? "", reason: attempt.overrideReason ?? "" }; if (!draft.band) return; setSaving(attempt.id); setError(""); try { await onOverride(attempt.id, draft.band, draft.reason); } catch (value) { setError((value as Error).message); } finally { setSaving(""); } }
  return <><header><div><span className="mobile-brand">مدیریت آموزشگاه</span><h1>تعیین سطح</h1><p>بررسی آزمون‌های انجام‌شده و ثبت سطح نهایی با نظر کارشناس.</p></div></header><section className="panel student-panel assessment-admin-panel"><div className="panel-title"><div><h2>آزمون‌های اخیر</h2><p>{attempts.length.toLocaleString("fa-IR")} آزمون ثبت شده</p></div></div>{error && <p className="form-error">{error}</p>}<div className="assessment-attempt-list">{attempts.length ? attempts.map((attempt) => { const draft = drafts[attempt.id] ?? { band: attempt.overrideBand ?? attempt.recommendedBand ?? "", reason: attempt.overrideReason ?? "" }; return <article key={attempt.id}><div><strong>{attempt.candidateName}</strong><small>{attempt.candidateMobile ?? "بدون شماره تماس"} · {attempt.language === "en" ? "انگلیسی" : "آلمانی"} · {attempt.ageBand === "child" ? "کودک" : attempt.ageBand === "teen" ? "نوجوان" : "بزرگسال"}</small></div><div><small>پیشنهاد سیستم</small><strong>{attempt.recommendedBand?.toUpperCase() ?? "در انتظار نتیجه"}</strong></div><div><small>امتیاز</small><strong>{attempt.score === null ? "—" : attempt.score.toLocaleString("fa-IR")}</strong></div><span className={"assessment-confidence " + (attempt.confidence ?? "pending")}>{attempt.confidence === "high" ? "اطمینان بالا" : attempt.confidence === "medium" ? "اطمینان متوسط" : attempt.confidence === "low" ? "اطمینان پایین" : "تکمیل نشده"}</span><div className="assessment-override"><label>سطح نهایی<select value={draft.band} onChange={(event) => updateDraft(attempt, "band", event.target.value)}><option value="">انتخاب سطح</option>{bands.map((band) => <option key={band} value={band}>{band.toUpperCase()}</option>)}</select></label><label>دلیل تغییر<textarea rows={1} value={draft.reason} onChange={(event) => updateDraft(attempt, "reason", event.target.value)} placeholder="اختیاری" /></label><button className="button secondary" disabled={saving === attempt.id || !draft.band} onClick={() => void save(attempt)}>{saving === attempt.id ? "در حال ذخیره..." : attempt.overrideBand ? "به‌روزرسانی سطح" : "ثبت سطح نهایی"}</button></div>{attempt.studentId ? <span className="assessment-linked">لید ثبت شده</span> : <button className="button secondary assessment-register" onClick={() => void onRegister(attempt.id)}>ثبت به‌عنوان لید</button>}<small>{attempt.submittedAt ? formatIranDateTime(attempt.submittedAt) : "هنوز ارسال نشده"}</small></article>; }) : <p className="empty-state">هنوز آزمونی انجام نشده است.</p>}</div></section></>;
}

function jalaliAge(value: string) {
  const match = /^(\d{4})\/(\d{1,2})\/(\d{1,2})$/.exec(value);
  if (!match) return 18;
  const today = new Intl.DateTimeFormat("fa-IR-u-ca-persian", { year: "numeric", month: "numeric", day: "numeric" }).formatToParts(new Date());
  const current = Number(today.find((part) => part.type === "year")?.value ?? 1403);
  return Math.max(0, current - Number(match[1]));
}
function escapeHtml(value: string) { return value.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;").replace(/\x27/g, "&#039;"); }
function printInvoice(invoice: InvoiceSummary) { const popup = window.open("", "_blank", "width=720,height=800"); if (!popup) return; const status = invoice.status === "paid" ? "تسویه‌شده" : invoice.status === "partial" ? "پرداخت ناقص" : "باز"; const safe = escapeHtml; popup.document.write(`<!doctype html><html lang="fa" dir="rtl"><head><meta charset="utf-8"><title>${safe(invoice.number)}</title><style>body{font-family:Tahoma,Arial,sans-serif;color:#17352c;padding:48px;line-height:2}header{display:flex;justify-content:space-between;border-bottom:2px solid #17352c;padding-bottom:18px}h1{font-size:24px;margin:0}h2{font-size:17px;margin-top:36px}table{width:100%;border-collapse:collapse;margin-top:18px}td{border-bottom:1px solid #ddd;padding:12px}td:first-child{color:#66766f}strong{font-size:18px}.note{margin-top:45px;color:#66766f;font-size:12px}@media print{body{padding:0}}</style></head><body><header><div><h1>زبانکده</h1><div>فاکتور شهریه</div></div><div><strong>${invoice.number}</strong><div>${status}</div></div></header><h2>مشخصات زبان‌آموز</h2><table><tr><td>نام</td><td>${safe(invoice.studentName)}</td></tr><tr><td>تاریخ سررسید</td><td>${safe(invoice.dueOn ?? "—")}</td></tr><tr><td>مبلغ کل</td><td>${invoice.totalRials.toLocaleString("fa-IR")} ریال</td></tr><tr><td>مانده قابل پرداخت</td><td><strong>${invoice.balanceRials.toLocaleString("fa-IR")} ریال</strong></td></tr></table><p class="note">این رسید توسط سامانه مدیریت آموزشگاه زبانکده صادر شده است.</p><script>window.onload=()=>window.print();</script></body></html>`); popup.document.close(); }
